-- Summit Planner: Seed Data
-- 15 Validated Objectives + Benchmark Exercises

-- ============================================
-- BENCHMARK EXERCISES
-- ============================================

INSERT INTO benchmark_exercises (id, name, description, dimension, tags, equipment_required, is_gym_reproducible, measurement_type, measurement_unit, difficulty_scale) VALUES

-- CARDIO benchmarks
('b1000000-0000-0000-0000-000000000001', 'Timed Loaded Step-Ups', 'Step up onto a 16-inch box with a loaded pack, alternating legs. Count total steps in 30 minutes.', 'cardio', '["heavy-pack", "gym-reproducible", "endurance"]', '{"16-inch box", "loaded pack"}', true, 'reps', 'reps', '{"beginner": "200 reps/30min @ 25lb", "intermediate": "400 reps/30min @ 25lb", "strong": "550 reps/30min @ 35lb", "elite": "700+ reps/30min @ 35lb"}'),

('b1000000-0000-0000-0000-000000000002', 'Sustained Zone 2 Run', 'Run at conversational pace (Zone 2 heart rate) for as long as possible. Record total distance and time.', 'cardio', '["running", "endurance", "zone-2"]', '{}', false, 'distance', 'miles', '{"beginner": "2-3 miles", "intermediate": "5-8 miles", "strong": "10-15 miles", "elite": "20+ miles"}'),

('b1000000-0000-0000-0000-000000000003', 'Uphill Hike with Pack', 'Hike uphill (treadmill 15% grade or outdoor trail) with a loaded pack. Record elevation gain in 60 minutes.', 'cardio', '["hiking", "heavy-pack", "altitude"]', '{"loaded pack"}', true, 'distance', 'feet of gain', '{"beginner": "1000 ft/hr", "intermediate": "1500 ft/hr", "strong": "2000 ft/hr", "elite": "2500+ ft/hr"}'),

-- STRENGTH benchmarks
('b2000000-0000-0000-0000-000000000001', 'Loaded Pack Squat', 'Back squat or goblet squat with loaded pack weight. Record max reps at prescribed weight.', 'strength', '["legs", "heavy-pack", "gym-reproducible"]', '{"barbell or dumbbells"}', true, 'reps', 'reps', '{"beginner": "10 reps @ bodyweight", "intermediate": "20 reps @ bodyweight", "strong": "15 reps @ 1.25x BW", "elite": "15 reps @ 1.5x BW"}'),

('b2000000-0000-0000-0000-000000000002', 'Single-Leg Step-Down', 'Stand on 12-inch box, slowly lower opposite foot to ground (3-second count), return. Record max controlled reps per leg.', 'strength', '["legs", "balance", "knee-stability"]', '{"12-inch box"}', true, 'reps', 'reps per leg', '{"beginner": "5 per leg", "intermediate": "15 per leg", "strong": "25 per leg", "elite": "35+ per leg"}'),

('b2000000-0000-0000-0000-000000000003', 'Weighted Pull-Ups', 'Pull-ups with additional weight. Record max reps at prescribed weight.', 'strength', '["upper-body", "climbing", "gym-reproducible"]', '{"pull-up bar", "weight belt"}', true, 'reps', 'reps', '{"beginner": "3 bodyweight", "intermediate": "8 bodyweight", "strong": "5 @ +25lb", "elite": "5 @ +45lb"}'),

('b2000000-0000-0000-0000-000000000004', 'Loaded Carry', 'Farmer carry or ruck march. Record distance covered with prescribed weight in 10 minutes.', 'strength', '["grip", "core", "heavy-pack", "endurance"]', '{"heavy dumbbells or loaded pack"}', true, 'distance', 'meters', '{"beginner": "200m @ 40lb", "intermediate": "400m @ 50lb", "strong": "500m @ 70lb", "elite": "600+ m @ 80lb"}'),

('b2000000-0000-0000-0000-000000000005', 'Push-Up Max Set', 'Strict push-ups, chest to ground, full lockout. Record max unbroken reps.', 'strength', '["upper-body", "endurance", "gym-reproducible"]', '{}', true, 'reps', 'reps', '{"beginner": "10", "intermediate": "25", "strong": "45", "elite": "70+"}'),

-- CLIMBING/TECHNICAL benchmarks
('b3000000-0000-0000-0000-000000000001', 'Top-Rope Climbing Assessment', 'Climb 5 routes at or near project grade. Record highest clean send grade.', 'climbing_technical', '["rock-climbing", "gym-reproducible"]', '{"climbing gym or outdoor crag"}', true, 'self_rated', 'grade', '{"beginner": "5.6-5.7", "intermediate": "5.9-5.10a", "strong": "5.10d-5.11b", "elite": "5.12+"}'),

('b3000000-0000-0000-0000-000000000002', 'Scramble Confidence Assessment', 'Self-rated comfort on exposed Class 3-4 terrain on a 1-5 scale. 1=terrified, 5=confident and fluid movement.', 'climbing_technical', '["scrambling", "exposure"]', '{}', false, 'self_rated', '1-5 scale', '{"beginner": "1-2", "intermediate": "3", "strong": "4", "elite": "5"}'),

('b3000000-0000-0000-0000-000000000003', 'Rope Skills Timed Test', 'Set up a standard anchor, rappel, and re-ascend. Record total time. Tests mechanical proficiency under mild stress.', 'climbing_technical', '["trad-climbing", "alpine"]', '{"climbing gear", "rope"}', false, 'time', 'minutes', '{"beginner": "30+ min", "intermediate": "15-20 min", "strong": "8-12 min", "elite": "<8 min"}'),

-- FLEXIBILITY benchmarks
('b4000000-0000-0000-0000-000000000001', 'Deep Squat Hold', 'Hold a full-depth squat (heels flat, chest up) for time. Record max hold duration.', 'flexibility', '["hip-mobility", "ankle-mobility", "gym-reproducible"]', '{}', true, 'time', 'seconds', '{"beginner": "15s", "intermediate": "45s", "strong": "90s", "elite": "180s+"}'),

('b4000000-0000-0000-0000-000000000002', 'Hip Flexor Stretch Assessment', 'Modified Thomas test. Self-rate hip flexor tightness 1-5 (1=very tight, 5=excellent range).', 'flexibility', '["hip-mobility"]', '{}', true, 'self_rated', '1-5 scale', '{"beginner": "1-2", "intermediate": "3", "strong": "4", "elite": "5"}'),

('b4000000-0000-0000-0000-000000000003', 'Ankle Dorsiflexion Test', 'Knee-to-wall test. Record max distance (inches) from wall with knee touching while heel stays flat.', 'flexibility', '["ankle-mobility", "gym-reproducible"]', '{}', true, 'distance', 'inches', '{"beginner": "2-3 inches", "intermediate": "4 inches", "strong": "5 inches", "elite": "6+ inches"}');


-- ============================================
-- VALIDATED OBJECTIVES (15 from spec)
-- ============================================

-- 1. Half Dome
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Half Dome', 'Mist Trail + Cables',  '{"half dome", "half dome mist trail", "half dome cables", "half dome yosemite"}', 'hike', 'intermediate', 'Iconic Yosemite summit via the Mist Trail and cable route. 14-16 mile day with 4,800ft gain and the famous cable section.', 8844, 4800, 14.5, 1, 'Class 2-3 (cables)', '["heavy-pack", "exposure", "endurance", "long-day"]',
'{"cardio":70,"strength":65,"climbing_technical":40,"flexibility":50}',
'{"cardio":"All-day hiking engine with pack","strength":"Leg endurance for steep terrain","climbing_technical":"Cable confidence with exposure comfort","flexibility":"Hip and ankle mobility"}',
'{"cardio":{"summary":"Half Dome demands sustained aerobic capacity for 8-10 hours of hiking with significant elevation gain. The cardiovascular system must efficiently process oxygen at altitude while managing fatigue accumulation over the long day.","keyComponents":["Sustained Zone 2 aerobic base","Uphill hiking endurance","Altitude adaptation capacity","Late-day fatigue resistance","Pack-loaded movement efficiency","Recovery between steep sections","Heart rate management on climbs","Breathing rhythm maintenance","Energy system pacing","Multi-hour work capacity"],"irrelevantComponents":["Sprint power","Anaerobic threshold intervals","Explosive cardio bursts","Short-duration high intensity","Cycling-specific fitness","Swimming endurance","Plyometric conditioning","Power endurance","Lactate tolerance","Competition pacing"]},"strength":{"summary":"Lower body strength endurance is critical for the sustained climbing and controlled descents. Core stability supports pack carrying while upper body strength aids the cable section and general mountain movement.","keyComponents":["Quadriceps endurance for sustained climbing","Calf strength for step-ups","Glute activation and power","Core stability with pack load","Grip strength for cable section","Eccentric quad control on descents","Hip stability on uneven terrain","Postural endurance","Pack-loaded movement patterns","Single-leg stability"],"irrelevantComponents":["Maximal strength","Olympic lifting","Bench press power","Overhead pressing","Heavy deadlifts","Powerlifting movements","Explosive power","Plyometric strength","Competition lifting","Isolation exercises"]},"climbing_technical":{"summary":"The cable section requires comfort with exposure and basic climbing movement. Scrambling skills help with the final approach while confidence on exposed terrain is essential for safety and enjoyment.","keyComponents":["Exposure comfort and management","Basic rock scrambling technique","Cable climbing mechanics","Footwork on granite slabs","Hand placement and grip","Mental composure on exposure","Route-finding on rock","Descent technique","Safety awareness"],"irrelevantComponents":["Advanced rock climbing grades","Trad gear placement","Multi-pitch systems","Rescue techniques","Ice climbing","Alpine climbing systems","Big wall techniques","Sport climbing","Bouldering power","Competition climbing"]},"flexibility":{"summary":"Hip and ankle mobility enable efficient hiking mechanics over varied terrain. Adequate flexibility prevents injury and maintains movement quality during the long day.","keyComponents":["Hip flexor length for step-ups","Ankle dorsiflexion for steep terrain","Calf flexibility for descents","Hip internal rotation","Thoracic spine mobility","Deep squat position","Dynamic movement patterns","Recovery positioning"],"irrelevantComponents":["Extreme flexibility","Yoga advanced poses","Overhead shoulder mobility","Spinal hyperextension","Gymnastic flexibility","Dance-specific mobility","Contortion abilities","Ballistic stretching","Competition flexibility","Passive flexibility extremes"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"7200 ft gain in 60 minutes","whyThisTarget":"150% of Half Dome''s elevation gain rate builds comfort buffer for the sustained climb."},{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"18 miles","whyThisTarget":"150% overshoot of Half Dome distance ensures aerobic base for the long day."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 reps per leg","whyThisTarget":"Strong eccentric control prevents quad fatigue on the long granite descent."},{"exerciseId":"b2000000-0000-0000-0000-000000000001","exerciseName":"Loaded Pack Squat","graduationTarget":"20 reps at bodyweight","whyThisTarget":"Leg strength endurance for thousands of step-ups over granite terrain."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4 on 1-5 scale","whyThisTarget":"Strong confidence on Class 3 exposure ensures safe and enjoyable cable section navigation."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"90 seconds","whyThisTarget":"Hip and ankle mobility for efficient hiking mechanics and recovery positions."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"5 inches","whyThisTarget":"Adequate ankle mobility prevents calf strain and enables efficient step placement on steep granite."}]}',
10, 'active');

-- 2. Colorado 14er Class 1-2
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Colorado 14er (Class 1-2)', 'Standard Routes (Quandary, Elbert, Bierstadt)',  '{"14er", "fourteener", "quandary peak", "mount elbert", "bierstadt", "colorado 14er", "14er class 1", "14er class 2"}', 'hike', 'beginner', 'Standard non-technical Colorado 14ers. Typically 6-14 miles with 3000-5000ft gain above 14,000ft.', 14265, 3500, 7, 1, 'Class 1-2', '["high-altitude", "endurance"]',
'{"cardio":60,"strength":45,"climbing_technical":25,"flexibility":40}',
'{"cardio":"Sustained hiking at altitude endurance","strength":"Leg power under load","climbing_technical":"Basic scrambling confidence","flexibility":"Hip and ankle mobility"}',
'{"cardio":{"summary":"Colorado 14ers demand sustained aerobic capacity at altitude for 6-8 hours of hiking. The primary challenge is maintaining steady output while oxygen availability drops significantly above 10,000 feet.","keyComponents":["aerobic base endurance","altitude acclimatization","sustained Zone 2 effort","uphill hiking efficiency","loaded pack tolerance","multi-hour energy systems","heart rate control at altitude","breathing rhythm under load","steady pace maintenance","fatigue resistance"],"irrelevantComponents":["anaerobic power","sprint intervals","explosive cardio","high-intensity intervals","VO2 max efforts","lactate threshold work","short burst capacity","recovery between efforts","speed endurance","tactical movements"]},"strength":{"summary":"Leg strength and muscular endurance are critical for sustained uphill hiking and controlled descents on loose terrain. Core stability supports pack carrying over long distances.","keyComponents":["quad strength for ascents","glute power for step-ups","calf endurance","single-leg stability","eccentric quad control for descents","core stability under load","pack-carrying capacity","hip flexor strength","ankle stability on loose rock","muscular endurance"],"irrelevantComponents":["upper body power","explosive movements","heavy lifting","maximal strength","Olympic lifts","plyometric power","bench press strength","pull-up capacity","grip strength","rotational power"]},"climbing_technical":{"summary":"Class 1-2 terrain requires basic scrambling skills and comfort on moderately exposed terrain. Route-finding and rock quality assessment become important on loose Colorado rock.","keyComponents":["basic scrambling technique","comfort on exposure","loose rock navigation","route-finding skills","three-point contact","balance on uneven terrain","fall consequence assessment","rock quality evaluation","basic self-arrest","confident movement on easy terrain"],"irrelevantComponents":["technical rock climbing","rope skills","anchor building","belaying","lead climbing","advanced rescue","ice climbing","mixed climbing","aid climbing","big wall techniques"]},"flexibility":{"summary":"Hip and ankle mobility enable efficient hiking stride and adaptation to uneven terrain. Adequate range of motion prevents overuse injuries during long ascents.","keyComponents":["hip flexor length","ankle dorsiflexion","calf flexibility","hip extension range","deep squat mobility","stride efficiency","step-up range of motion","IT band mobility","hamstring length","dynamic movement patterns"],"irrelevantComponents":["extreme flexibility","overhead mobility","spinal rotation","advanced yoga poses","shoulder flexibility","wrist mobility","neck range of motion","thoracic extension","advanced stretching","contortionist abilities"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2200 ft/hr with 25lb pack","whyThisTarget":"Exceeds the objective''s 3500ft gain over ~7 hours to build comfortable buffer for altitude and pack weight."},{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"10+ miles","whyThisTarget":"Builds aerobic base well beyond the 7-mile objective distance for sustained high-altitude effort."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"15 per leg","whyThisTarget":"Provides quad strength and control needed for thousands of steps on descent with loose rock."},{"exerciseId":"b1000000-0000-0000-0000-000000000001","exerciseName":"Timed Loaded Step-Ups","graduationTarget":"400 reps/30min @ 25lb","whyThisTarget":"Simulates repetitive uphill hiking motion with pack weight for sustained muscular endurance."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"3 on 1-5 scale","whyThisTarget":"Class 1-2 terrain occasionally approaches Class 3 on loose Colorado rock, requiring basic scrambling confidence."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"45 seconds","whyThisTarget":"Ensures hip and ankle mobility for efficient hiking stride and rock step-overs."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4 inches","whyThisTarget":"Provides ankle range of motion needed for steep uphill hiking and uneven terrain navigation."}]}',
6, 'active');

-- 3. Mt. Whitney
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Mt. Whitney', 'Main Trail (Whitney Trail)',  '{"mt whitney", "mount whitney", "whitney", "whitney main trail", "whitney portal"}', 'hike', 'intermediate', 'Highest peak in the contiguous US via the Main Trail. 22-mile round trip with 6,100ft gain.', 14505, 6100, 22, 1, 'Class 1', '["high-altitude", "endurance", "long-day"]',
'{"cardio":75,"strength":65,"climbing_technical":25,"flexibility":50}',
'{"cardio":"All-day endurance at thin air","strength":"Load-bearing legs for endless miles","climbing_technical":"Trail navigation and basic scrambling","flexibility":"Hip and ankle mobility for long days"}',
'{"cardio":{"summary":"Whitney demands exceptional aerobic endurance for 10-14 hours of continuous hiking at high altitude. The combination of 22-mile distance, 6,100ft elevation gain, and 14,505ft summit elevation creates a severe cardiovascular challenge requiring sustained Zone 2 output with altitude adaptation.","keyComponents":["sustained aerobic power for 10-14 hours","altitude adaptation above 10,000ft","uphill hiking endurance with elevation gain","Zone 2 heart rate maintenance","long-distance hiking economy","fatigue resistance over marathon distances","oxygen utilization at thin air","steady-state energy system development","mental endurance for long efforts","recovery between sustained climbs"],"irrelevantComponents":["anaerobic power intervals","sprint speed","explosive cardio bursts","high-intensity interval work","lactate threshold training","VO2 max intervals","short-duration cardio","power hiking bursts","racing pace","competitive cardio fitness"]},"strength":{"summary":"Leg strength and endurance dominate Whitney''s demands, with focus on load-bearing capacity for long miles and steep terrain. Core stability supports pack carrying and maintains hiking posture over the extended duration.","keyComponents":["quadriceps endurance for long descents","glute strength for sustained uphill hiking","calf endurance for continuous stepping","hip stability over uneven terrain","core endurance for posture maintenance","pack-carrying strength","knee stability for long descents","single-leg strength for trail obstacles","grip strength for trekking poles","lower back endurance"],"irrelevantComponents":["upper body pulling strength","overhead pressing power","explosive lower body power","heavy deadlifting strength","bench press capacity","weighted pull-ups","Olympic lifting movements","maximum strength testing","power cleans","heavy carrying for short distances"]},"climbing_technical":{"summary":"Whitney''s Main Trail is Class 1 hiking with minimal technical demands. The primary skills involve trail navigation, basic scrambling confidence, and movement efficiency over varied terrain for extended periods.","keyComponents":["trail route-finding ability","basic scrambling on loose rock","efficient hiking movement patterns","terrain reading skills","confidence on exposed trail sections","basic balance on uneven surfaces","rock hopping technique","steep trail navigation","switchback efficiency","fatigue-resistant movement"],"irrelevantComponents":["rock climbing technique","rope handling skills","belaying competence","anchor building","rappelling ability","multi-pitch systems","aid climbing technique","crack climbing skills","face climbing technique","advanced route-finding"]},"flexibility":{"summary":"Hip and ankle mobility support efficient hiking stride and prevent injury over 22 miles. Adequate flexibility prevents compensation patterns that lead to overuse injuries during the long day.","keyComponents":["hip flexor length for long hiking strides","ankle dorsiflexion for steep uphill sections","calf flexibility for extended walking","IT band mobility for lateral stability","hip external rotation for varied terrain","thoracic spine mobility for pack carrying","hamstring flexibility for long descents","deep squat mobility for rest positions","hip internal rotation for trail obstacles","plantar fascia mobility"],"irrelevantComponents":["shoulder overhead mobility","spinal hyperextension","extreme hip flexion","advanced yoga positions","gymnastic-level flexibility","overhead reaching mobility","wrist and forearm flexibility","neck rotation range","finger flexibility","advanced stretching positions"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"15 miles at conversational pace","whyThisTarget":"Builds the aerobic base needed for Whitney''s 22-mile distance with 50% overshoot for comfort."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2500 ft elevation gain in 60 minutes with 20lb pack","whyThisTarget":"Exceeds Whitney''s sustained climbing demands and prepares for the altitude challenge."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 controlled reps per leg","whyThisTarget":"Provides the quad strength and knee stability needed for Whitney''s long descent without injury."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500m in 10 minutes with 50lb pack","whyThisTarget":"Builds the load-carrying capacity and core endurance needed for long-distance pack hiking."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4 on 1-5 confidence scale","whyThisTarget":"Ensures comfort with basic scrambling and exposure that may be encountered on Whitney''s summit approach."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"90 seconds","whyThisTarget":"Ensures adequate hip and ankle mobility for efficient hiking stride over Whitney''s 22-mile distance."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"5 inches knee-to-wall distance","whyThisTarget":"Provides the ankle mobility needed for steep uphill hiking sections without compensation patterns."}]}',
12, 'active');

-- 4. Mont Blanc
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Mont Blanc', 'Goûter Route (Voie Normale)',  '{"mont blanc", "mont blanc normal route", "mont blanc gouter", "mont blanc from saint-gervais"}', 'mountaineering', 'advanced', 'Highest peak in the Alps via the standard Goûter Route. 2-day climb with glacier travel and altitude sickness risk.', 15781, 5200, 11, 2, 'PD', '["high-altitude", "glacier", "multi-day", "heavy-pack"]',
'{"cardio":75,"strength":70,"climbing_technical":60,"flexibility":50}',
'{"cardio":"Sustained alpine endurance at altitude","strength":"Heavy pack leg power","climbing_technical":"Glacier travel and exposure comfort","flexibility":"Hip mobility for crampon steps"}',
'{"cardio":{"summary":"Mont Blanc demands sustained aerobic power over two days at high altitude with significant pack weight. The Goûter Route requires efficient uphill hiking endurance with reserves for altitude effects and multi-day fatigue.","keyComponents":["uphill hiking endurance with heavy pack","altitude tolerance above 12,000 feet","multi-day energy management","sustained Zone 2 aerobic capacity","recovery between climbing days","efficient movement under load","cardiovascular reserve for emergencies","cold weather performance maintenance","steady pace on technical terrain","endurance with reduced oxygen"],"irrelevantComponents":["sprint intervals","anaerobic power","explosive cardio movements","short high-intensity bursts","sea-level VO2 max","running speed","agility cardio","quick recovery intervals","power endurance","lactate threshold training"]},"strength":{"summary":"Heavy pack load bearing and sustained leg strength for steep alpine terrain. Focus on load-bearing endurance rather than maximal strength, with particular emphasis on uphill hiking power.","keyComponents":["heavy pack load bearing","sustained uphill hiking strength","leg endurance under load","postural strength with pack","grip strength for ice axe","core stability on uneven terrain","single-leg stability on steep ground","load carrying capacity","fatigue-resistant leg strength","knee stability on descent"],"irrelevantComponents":["maximal deadlift strength","explosive power movements","upper body pressing power","gymnastic strength","short-duration max efforts","bodyweight strength ratios","pull-up capacity","bench press strength","Olympic lifting","plyometric power"]},"climbing_technical":{"summary":"Basic glacier travel skills, crampon technique, and comfort on moderate alpine terrain. The Goûter Route requires fundamental mountaineering skills rather than advanced technical climbing.","keyComponents":["crampon walking technique","ice axe self-arrest","basic glacier travel","roped team movement","crevasse rescue basics","route finding on glaciers","comfort on exposed terrain","basic anchor building","rappelling proficiency","movement in mountaineering boots"],"irrelevantComponents":["advanced ice climbing","multi-pitch rock skills","aid climbing technique","advanced rescue systems","big wall efficiency","sport climbing grades","bouldering power","trad gear placement","free climbing difficulty","competition climbing skills"]},"flexibility":{"summary":"Adequate hip and ankle mobility for efficient crampon technique and comfortable movement in mountaineering boots. Basic flexibility to prevent injury during long days with heavy packs.","keyComponents":["hip flexor mobility for high steps","ankle dorsiflexion for crampon technique","calf flexibility for steep terrain","hip mobility for pack comfort","thoracic spine mobility","shoulder mobility for pack straps","hamstring flexibility for step-ups","adequate range of motion in boots"],"irrelevantComponents":["advanced yoga poses","extreme flexibility","overhead mobility","spinal hyperextension","gymnastic flexibility","dance-level mobility","extreme hip external rotation","advanced stretching techniques","contortionist abilities","competitive flexibility standards"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"1800 ft gain/hour @ 35lb pack","whyThisTarget":"Overshoot target for 5200ft objective ensures comfortable pace with reserves for altitude effects."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Ensures knee stability and control on steep descent sections of the Goûter Route."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"450m in 10min @ 60lb","whyThisTarget":"Builds pack-carrying endurance for multi-day mountaineering with heavy winter gear."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4 on 1-5 scale","whyThisTarget":"Confident movement on exposed terrain is essential for the Goûter Route''s rocky sections and glacier travel."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Adequate hip and ankle mobility for efficient crampon technique and comfortable mountaineering boot movement."}]}',
14, 'active');

-- 5. Mt. Rainier
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Mt. Rainier', 'Disappointment Cleaver',  '{"mt rainier", "mount rainier", "rainier", "rainier dc", "disappointment cleaver"}', 'mountaineering', 'advanced', 'Pacific Northwest iconic volcano via the standard DC route. 2-3 day climb with glacier travel.', 14411, 9000, 16, 2, 'PD-', '["high-altitude", "glacier", "multi-day", "heavy-pack"]',
'{"cardio":75,"strength":70,"climbing_technical":40,"flexibility":45}',
'{"cardio":"Sustained aerobic power with heavy pack","strength":"Load-bearing endurance for glacier travel","climbing_technical":"Basic rope skills and crampon technique","flexibility":"Hip and ankle mobility for crampon use"}',
'{"cardio":{"summary":"Rainier demands exceptional aerobic endurance to handle 9,000 feet of elevation gain over 2-3 days while carrying a heavy pack at altitude. The cardiovascular system must efficiently process oxygen in thin air while sustaining moderate intensity effort for extended periods.","keyComponents":["Heavy pack endurance","Sustained aerobic base","Altitude adaptation capacity","Multi-day energy management","Uphill hiking efficiency","Recovery between climbing days","Zone 2 aerobic development","Pack weight tolerance","Extended duration stamina","Elevation gain capacity"],"irrelevantComponents":["Sprint power","Anaerobic threshold","High-intensity intervals","Explosive cardio bursts","Short-duration max efforts","Speed endurance","Lactate tolerance","VO2 max intervals","Racing pace","Time trial performance"]},"strength":{"summary":"Strength demands focus on load-bearing endurance for extended uphill travel with a heavy pack, plus the stability and power needed for glacier travel with crampons. Emphasis on functional strength that prevents injury over multiple days.","keyComponents":["Heavy pack carrying capacity","Lower body endurance strength","Postural endurance with load","Single-leg stability","Hip and glute activation","Core stability under load","Grip endurance for tools","Eccentric leg control","Balance with crampons","Multi-day durability"],"irrelevantComponents":["Maximum strength lifts","Olympic lift power","Explosive power development","Heavy deadlifts","Bench press strength","Short-duration max efforts","Bodybuilding isolation","Heavy overhead pressing","Competition lifting","Pure strength testing"]},"climbing_technical":{"summary":"Technical demands are relatively low for the DC route - basic glacier travel skills, crampon technique, and fundamental rope skills for crevasse rescue. Focus on competent execution of standard mountaineering techniques rather than advanced climbing ability.","keyComponents":["Basic rope handling","Crampon walking technique","Self-arrest with axe","Crevasse rescue basics","Glacier travel awareness","Team rope management","Basic anchor skills","Route finding on glaciers","Weather assessment","Emergency procedures"],"irrelevantComponents":["Advanced rock climbing","Multi-pitch trad skills","Aid climbing technique","Big wall systems","Sport climbing grades","Bouldering strength","Competition climbing","Free climbing difficulty","Technical rescue","Advanced anchor systems"]},"flexibility":{"summary":"Flexibility needs center on hip and ankle mobility for efficient crampon use and the deep stepping motions required in snow and on glaciers. Adequate range of motion prevents injury and improves movement efficiency over long days.","keyComponents":["Deep squat mobility for crampon adjustment","Hip flexor length for step-ups","Ankle dorsiflexion for crampon fit","Calf flexibility for heel cups","Hip mobility for high steps","Achilles flexibility","Deep knee bend capability","Comfortable gear harness fit","Boot flexibility adaptation","Multi-day movement maintenance"],"irrelevantComponents":["Extreme flexibility","Gymnastic range of motion","Advanced yoga poses","Overhead shoulder mobility","Spinal hyperextension","Competition flexibility","Dance-level mobility","Contortion abilities","Advanced stretching","Hypermobility training"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2200 ft/hr @ 40lb pack","whyThisTarget":"Exceeds Rainier''s sustained climb rate with full mountaineering pack weight for crevasse rescue gear and multi-day supplies."},{"exerciseId":"b1000000-0000-0000-0000-000000000001","exerciseName":"Timed Loaded Step-Ups","graduationTarget":"500 reps/30min @ 35lb pack","whyThisTarget":"Builds specific hip flexor endurance needed for sustained uphill travel with the repetitive stepping motion required on Rainier''s long approach and summit day."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"450m @ 50lb pack","whyThisTarget":"Matches typical Rainier pack weight for multi-day climb with safety gear, food, and shelter while building load-bearing endurance."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Ensures adequate single-leg stability and eccentric control needed for safe crampon travel on variable glacier terrain."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000003","exerciseName":"Rope Skills Timed Test","graduationTarget":"12-15 minutes","whyThisTarget":"Demonstrates competent rope handling for crevasse rescue scenarios and basic glacier travel safety on Rainier''s heavily crevassed sections."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Ensures adequate ankle and hip mobility for comfortable crampon adjustments and the deep knee bend positions required in mountaineering boots."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4.5 inches","whyThisTarget":"Provides the ankle mobility needed for proper crampon fit and efficient walking technique in rigid mountaineering boots during long glacier approach."}]}',
14, 'active');

-- 6. Denali
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Denali', 'West Buttress',  '{"denali", "denali west buttress", "mt mckinley", "mount mckinley"}', 'mountaineering', 'expert', 'Highest peak in North America. 17-21 day expedition with extreme altitude, cold, and heavy loads.', 20310, 13000, 32, 18, 'AD-', '["high-altitude", "glacier", "multi-day", "heavy-pack", "extreme-cold"]',
'{"cardio":85,"strength":80,"climbing_technical":35,"flexibility":45}',
'{"cardio":"Relentless uphill endurance with heavy loads","strength":"Bulletproof legs and load carrying power","climbing_technical":"Basic glacier travel and rope skills","flexibility":"Essential mobility for crampon walking"}',
'{"cardio":{"summary":"Denali demands exceptional aerobic capacity for 18+ days of continuous uphill travel with heavy packs at extreme altitude. The cardiovascular system must efficiently deliver oxygen in thin air while maintaining steady effort for 6-10 hours daily.","keyComponents":["Sustained uphill hiking capacity","Heavy pack endurance","Altitude adaptation efficiency","Multi-day recovery between efforts","Zone 2 aerobic base","Steep terrain stamina","Cold weather performance","Load-bearing cardiovascular fitness","Extended duration tolerance","Oxygen-deprived performance"],"irrelevantComponents":["Sprint speed","Anaerobic power","Change of direction agility","Short burst intervals","Running economy on flat terrain","High-intensity lactate tolerance","Plyometric explosiveness","Sport-specific ball skills","Fine motor coordination under fatigue","Speed endurance"]},"strength":{"summary":"Denali requires exceptional leg strength and core stability to carry 60+ pound packs uphill for weeks while maintaining balance on glaciated terrain. Upper body strength supports rope work and camp tasks in harsh conditions.","keyComponents":["Heavy pack carrying capacity","Uphill hiking leg strength","Single-leg stability and balance","Core strength under load","Grip strength for ice tools","Postural endurance with pack","Knee stability on uneven terrain","Hip power for steep steps","Functional upper body strength","Load-bearing muscular endurance"],"irrelevantComponents":["Maximum bench press","Olympic lifting technique","Isolation muscle training","Bodybuilding aesthetics","High-rep circuit training","Sport-specific power movements","Explosive jumping ability","Fine motor dexterity","Competitive lifting standards","Machine-based strength training"]},"climbing_technical":{"summary":"Denali''s West Buttress requires basic mountaineering skills including glacier travel, crevasse rescue, and crampon walking, but minimal technical rock or ice climbing. Rope team travel and basic anchor systems are essential.","keyComponents":["Crampon walking technique","Glacier travel rope team skills","Basic crevasse rescue","Snow camping setup","Ice axe self-arrest","Route finding on glaciers","Anchor building basics","Rope management","Weather assessment skills","Basic mountaineering movement"],"irrelevantComponents":["Advanced rock climbing grades","Sport climbing technique","Bouldering power moves","Multi-pitch trad skills","Technical ice climbing","Aid climbing systems","Big wall hauling","Competition climbing training","Dynos and coordination moves","Crack climbing technique"]},"flexibility":{"summary":"Denali requires sufficient mobility for crampon walking, deep knee bends with heavy packs, and comfortable positions during extended tent time. Focus on hip and ankle mobility essential for mountaineering movement patterns.","keyComponents":["Hip flexor mobility for high steps","Ankle dorsiflexion for crampon walking","Deep squat position for camp tasks","Hamstring flexibility for pack bending","Calf flexibility for steep terrain","Lower back mobility under load","Hip external rotation","Shoulder mobility for pack adjustments","Spinal rotation for terrain navigation","General movement efficiency"],"irrelevantComponents":["Extreme flexibility ranges","Gymnastics-level mobility","Sport-specific flexibility","Advanced yoga positions","Overhead flexibility extremes","Ballistic stretching","Competition flexibility standards","Dance-level range of motion","Contortion abilities","Performance flexibility demonstrations"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2000+ ft/hr @ 50lb pack","whyThisTarget":"Exceeds Denali''s typical 1300 ft/hr gain rate to build comfort buffer for altitude and fatigue."},{"exerciseId":"b1000000-0000-0000-0000-000000000001","exerciseName":"Timed Loaded Step-Ups","graduationTarget":"500+ reps/30min @ 50lb","whyThisTarget":"Develops specific uphill endurance with expedition pack weight to simulate continuous climbing days."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500m @ 60lb in 10min","whyThisTarget":"Matches typical Denali expedition pack weight for extended carries between camps."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 per leg controlled","whyThisTarget":"Ensures knee stability and eccentric strength for long descents with heavy pack loads."},{"exerciseId":"b2000000-0000-0000-0000-000000000001","exerciseName":"Loaded Pack Squat","graduationTarget":"15 reps @ 60lb pack weight","whyThisTarget":"Builds leg strength to handle expedition pack weight during deep knee bends and camp tasks."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000003","exerciseName":"Rope Skills Timed Test","graduationTarget":"15 minutes or less","whyThisTarget":"Ensures efficient rope work for crevasse rescue and anchoring systems required on glaciated terrain."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"45+ seconds","whyThisTarget":"Enables comfortable positions for camp tasks and crampon adjustments with expedition gear."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4+ inches","whyThisTarget":"Provides adequate ankle mobility for efficient crampon walking on varied glacial terrain."}]}',
20, 'active');

-- 7. Grand Teton
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Grand Teton', 'Upper Exum Ridge',  '{"grand teton", "grand teton exum", "exum ridge", "upper exum"}', 'alpine_climb', 'advanced', 'Classic alpine rock climb in the Tetons. Technical 5.5 climbing with serious exposure.', 13775, 7000, 12, 1, '5.5', '["trad-climbing", "exposure", "alpine", "heavy-pack"]',
'{"cardio":75,"strength":70,"climbing_technical":65,"flexibility":55}',
'{"cardio":"Sustained power for big vertical","strength":"Pack-loaded legs and climbing strength","climbing_technical":"Exposed 5.5 with alpine systems","flexibility":"High steps and ankle mobility"}',
'{"cardio":{"summary":"Grand Teton via Upper Exum requires sustained aerobic power for 7,000 feet of elevation gain over 12 miles, often with a heavy pack. The approach and descent demand excellent cardiovascular endurance at altitude with the ability to recover quickly between technical sections.","keyComponents":["Sustained uphill hiking power","Pack-loaded endurance","Altitude tolerance","Recovery between pitches","Long-duration aerobic capacity","Steep terrain efficiency","Energy conservation","Multi-hour sustained effort","Variable pace adaptation"],"irrelevantComponents":["Sprint speed","Anaerobic power","Track running economy","Flat terrain efficiency","Short burst recovery","Speed endurance","Racing tactics","Interval training specificity","Bike fitness crossover"]},"strength":{"summary":"The route demands strong legs for the massive approach with a heavy pack, plus upper body and grip strength for technical 5.5 climbing. Core stability is critical for exposure and pack-loaded movement on technical terrain.","keyComponents":["Pack-loaded hiking strength","Steep uphill power","Climbing-specific pull strength","Grip endurance","Core stability under load","Single-leg stability","Hip flexor strength","Shoulder endurance","Ankle/calf strength"],"irrelevantComponents":["Bench press strength","Maximum squat power","Explosive jumping","Sprint mechanics","Heavy overhead pressing","Powerlifting specificity","Bilateral leg pressing","Isolation exercises","Bodybuilding volume"]},"climbing_technical":{"summary":"Upper Exum requires confident movement on exposed 5.5 terrain with alpine climbing systems knowledge. The technical demands include traditional protection placement, rope management, and efficient movement with a pack on multi-pitch terrain.","keyComponents":["5.5+ climbing ability","Exposure comfort","Traditional protection skills","Multi-pitch efficiency","Alpine rope systems","Pack-loaded climbing","Route-finding skills","Gear placement confidence","Movement efficiency"],"irrelevantComponents":["Sport climbing tactics","Bouldering power","Crack climbing specialization","Advanced aid techniques","Competition climbing","High-grade redpointing","Dynamic movement","Campus board training","Finger strength protocols"]},"flexibility":{"summary":"The route requires good hip and ankle mobility for high steps and steep terrain navigation with a pack. Adequate flexibility prevents injury during the long approach and technical climbing sections.","keyComponents":["Hip flexor mobility","Deep squat range","Ankle dorsiflexion","Hip external rotation","Thoracic spine extension","Shoulder overhead reach","Hamstring flexibility","Calf flexibility"],"irrelevantComponents":["Extreme backbending","Split flexibility","Advanced yoga poses","Contortion-level range","Dance-specific mobility","Gymnastic flexibility","Oversplit training","Extreme hip mobility","Competition flexibility"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3000+ ft/hr with 35lb pack","whyThisTarget":"Exceeds the route''s 7000ft gain demand to build comfort buffer for sustained alpine pace."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Ensures single-leg stability and control for steep, uneven alpine terrain."},{"exerciseId":"b2000000-0000-0000-0000-000000000003","exerciseName":"Weighted Pull-Ups","graduationTarget":"6 bodyweight pull-ups","whyThisTarget":"Provides adequate upper body strength for sustained 5.5 climbing moves."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"400m in 10min with 40lb pack","whyThisTarget":"Builds pack-carrying endurance and core stability for the long approach."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000001","exerciseName":"Top-Rope Climbing Assessment","graduationTarget":"Clean 5.7 grade","whyThisTarget":"Two sub-grades above 5.5 objective provides comfortable margin for alpine conditions."},{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4 on 1-5 scale","whyThisTarget":"High confidence needed for Upper Exum''s serious exposure and commitment."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Ensures adequate hip and ankle mobility for high steps and steep terrain."}]}',
12, 'active');

-- 8. Cathedral Peak
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Cathedral Peak', 'Southeast Buttress',  '{"cathedral peak", "cathedral peak se buttress", "cathedral peak tuolumne"}', 'rock_climb', 'intermediate', 'Classic Tuolumne granite climb. 5-6 pitches at 5.6.', 10911, 2800, 8, 1, '5.6', '["trad-climbing", "exposure", "granite"]',
'{"cardio":65,"strength":70,"climbing_technical":75,"flexibility":55}',
'{"cardio":"Sustained hiking to base climbing","strength":"Granite friction and pack hauling","climbing_technical":"Multi-pitch trad on granite slabs","flexibility":"Hip mobility for slab positioning"}',
'{"cardio":{"summary":"Cathedral Peak requires steady hiking endurance to reach the base, then sustained movement over 5-6 pitches of moderate climbing. The approach involves 2800 feet of elevation gain over several miles, demanding aerobic capacity without exhausting reserves needed for technical climbing.","keyComponents":["sustained hiking pace at altitude","recovery between climbing pitches","maintaining energy through long day","hiking with climbing gear","uphill endurance capacity","aerobic base for multi-hour effort","pace management over varied terrain","cardiovascular efficiency at 10,000+ feet"],"irrelevantComponents":["sprint power","anaerobic threshold","interval training","high-intensity bursts","lactate tolerance","VO2 max power","speed work","race-pace efforts","explosive cardio movements","short-duration high intensity"]},"strength":{"summary":"Tuolumne granite demands specific pulling strength for crack and face climbing, plus core stability for slab positioning. Lower body strength supports the approach hike with climbing gear and maintains stability on exposed granite friction moves.","keyComponents":["pulling strength for cracks","grip endurance on granite","core stability for slab climbing","leg strength for friction moves","shoulder stability for reaches","forearm endurance","hiking strength with gear","mantling power","sustained grip strength","postural strength for exposure"],"irrelevantComponents":["maximum deadlift strength","explosive power movements","heavy overhead pressing","olympic lifting","plyometric power","maximum squat strength","powerlifting movements","ballistic training","heavy loaded carries beyond approach needs","maximum strength endurance"]},"climbing_technical":{"summary":"The Southeast Buttress requires solid 5.6 trad climbing skills on Tuolumne''s unique granite. This includes efficient movement on slabs, crack technique, and multi-pitch rope management systems in exposed terrain.","keyComponents":["5.6+ granite slab technique","crack climbing fundamentals","multi-pitch efficiency","trad gear placement","route finding on granite","exposure comfort","rope management systems","belay stance setup","granite friction footwork","efficient movement patterns"],"irrelevantComponents":["sport climbing redpoint tactics","advanced aid climbing","ice climbing technique","alpine mixed climbing","big wall hauling systems","speed climbing","bouldering power moves","competition climbing","indoor plastic technique","rescue systems beyond basic"]},"flexibility":{"summary":"Granite slab climbing requires hip mobility for high steps and wide stems, plus ankle flexibility for optimal friction contact. The long approach and multi-pitch nature demands sustained mobility throughout the day.","keyComponents":["hip flexion for high steps","hip external rotation for stems","ankle dorsiflexion for slab contact","thoracic spine mobility for reaches","shoulder flexibility for wide moves","sustained mobility through long day","recovery positioning between pitches","efficient rest positions"],"irrelevantComponents":["extreme flexibility","gymnastic-level mobility","advanced yoga poses","hypermobility","contortion-level flexibility","dance-specific mobility","splits flexibility","extreme spinal extension","circus-level flexibility","overhead flexibility beyond climbing needs"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2000 ft/hr for 60 minutes with 15lb pack","whyThisTarget":"Builds capacity for the 2800ft approach with climbing gear while maintaining energy for technical climbing."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000003","exerciseName":"Weighted Pull-Ups","graduationTarget":"8 bodyweight pull-ups","whyThisTarget":"Provides pulling strength reserve for sustained granite crack and face climbing through multiple pitches."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Builds leg stability and control essential for precise granite slab footwork and friction moves."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000001","exerciseName":"Top-Rope Climbing Assessment","graduationTarget":"Clean 5.8 grade","whyThisTarget":"Two sub-grades above 5.6 objective provides comfort margin for granite slab technique and exposure."},{"exerciseId":"b3000000-0000-0000-0000-000000000003","exerciseName":"Rope Skills Timed Test","graduationTarget":"Complete in 15 minutes","whyThisTarget":"Efficient multi-pitch systems are essential for timely completion of 5-6 pitch route."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Hip and ankle mobility needed for granite slab positioning and high steps on Tuolumne rock."}]}',
10, 'active');

