rescue","Advanced climbing movement"]},"flexibility":{"summary":"Mobility supports efficient running stride and reduces injury risk over long distances with significant elevation change. Hip and ankle mobility are particularly important for trail running mechanics.","keyComponents":["Hip flexor mobility","Ankle dorsiflexion","Calf flexibility","IT band mobility","Glute activation","Hip extension range","Stride length optimization","Dynamic flexibility","Recovery stretching","Movement efficiency"],"irrelevantComponents":["Extreme flexibility","Contortion","Advanced yoga poses","Overhead mobility","Spinal rotation","Deep backbending","Shoulder flexibility","Wrist mobility","Advanced stretching","Static flexibility extremes"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"20 miles","whyThisTarget":"150% overshoot of race distance builds aerobic base and confidence for 13.1-mile event."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"6000 ft/hr","whyThisTarget":"150% overshoot of race elevation gain ensures power for sustained climbing throughout the event."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 per leg","whyThisTarget":"Eccentric control prevents quad fatigue and maintains form during long descents."},{"exerciseId":"b2000000-0000-0000-0000-000000000005","exerciseName":"Push-Up Max Set","graduationTarget":"25 reps","whyThisTarget":"Basic upper body endurance supports arm swing and posture over 13+ miles."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"3 (confident)","whyThisTarget":"Basic terrain confidence handles any technical trail sections or off-trail navigation."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"45 seconds","whyThisTarget":"Hip and ankle mobility supports efficient uphill stride mechanics."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4 inches","whyThisTarget":"Adequate ankle mobility prevents calf tightness and maintains stride efficiency on climbs."}]}',
