INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('50K Mountain Ultra', '~8,000ft Gain',  '{"50k ultra", "50k mountain ultra", "ultramarathon", "ultra trail", "50k trail"}', 'trail_run', 'advanced', 'Mountain ultramarathon with approximately 8,000ft of elevation gain over 31 miles.', null, 8000, 31, 1, null, '["running", "ultra-endurance", "trail"]',
'{"cardio":85,"strength":70,"climbing_technical":15,"flexibility":55}',
'{"cardio":"Relentless aerobic engine for hours","strength":"Bulletproof legs and core durability","climbing_technical":"Basic trail navigation skills only","flexibility":"Essential mobility for injury prevention"}',
'{"cardio":{"summary":"The 50K mountain ultra demands exceptional aerobic endurance and uphill power over 6-10 hours of continuous movement. Your cardiovascular system must efficiently process oxygen while managing the metabolic demands of sustained climbing and descending across varied terrain.","keyComponents":["Zone 2 aerobic base for fat burning efficiency","Sustained uphill power at marathon effort","Downhill running eccentric strength endurance","Heat dissipation during prolonged exercise","Metabolic flexibility between fat and carb burning","Mental endurance for 6+ hour efforts","Pace management across elevation changes","Recovery between surges on technical terrain","Breathing efficiency at sustained efforts","Cardiovascular adaptation to altitude changes"],"irrelevantComponents":["Sprint speed and acceleration","Short interval power (under 5 minutes)","Anaerobic lactate tolerance","Explosive VO2max intervals","Track speed endurance","High-intensity threshold intervals","Recovery between high-intensity bouts","Neuromuscular power","Competition tactics and surging","Road racing specific pacing"]},"strength":{"summary":"Mountain ultras require bulletproof legs capable of thousands of steps uphill and eccentric control on descents, plus core stability for efficient movement over technical terrain. Strength endurance trumps maximal strength.","keyComponents":["Quad strength for sustained uphill hiking","Glute activation and endurance","Eccentric quad control for downhill running","Calf endurance for continuous push-off","Core stability for technical terrain","Hip flexor endurance for high stepping","Lower back endurance for forward lean","Hamstring strength for steep descents","Single-leg stability on uneven ground","Grip endurance for trekking poles"],"irrelevantComponents":["Maximum deadlift or squat strength","Explosive jumping power","Heavy overhead pressing","Bench press strength","Olympic lifting movements","High-load barbell training","Powerlifting-specific strength","Upper body muscular endurance beyond poles","Heavy farmer carries beyond 50lbs","Short-duration maximum efforts"]},"climbing_technical":{"summary":"Technical skills are minimal for most 50K mountain ultras - basic trail navigation, simple scrambling, and confident movement on loose terrain. No rope work or advanced climbing required.","keyComponents":["Basic route finding on marked trails","Confident movement on loose rock","Simple Class 2 scrambling comfort","Reading terrain for efficient lines","Basic safety awareness on exposure","Efficient use of trekking poles","Stream crossing techniques","Navigation with GPS or map","Risk assessment on technical sections","Efficient movement through boulder fields"],"irrelevantComponents":["Rock climbing grades above Class 2","Rope work and belaying skills","Advanced anchor building","Multi-pitch climbing techniques","Rappelling and ascending skills","Technical rescue techniques","Advanced scrambling on Class 4+","Ice climbing techniques","Alpine climbing systems","Traditional climbing protection"]},"flexibility":{"summary":"Mountain ultras demand adequate hip and ankle mobility to maintain efficient stride mechanics over thousands of steps, plus the ability to adapt to varied terrain without injury.","keyComponents":["Hip flexor length for uphill stride","Ankle dorsiflexion for steep terrain","Calf flexibility for heel striking","IT band mobility for lateral stability","Hamstring flexibility for stride length","Hip rotation for uneven terrain adaptation","Thoracic spine mobility for pole use","Glute activation and length balance","Lower back extension for sustained forward lean","Overall movement quality and efficiency"],"irrelevantComponents":["Extreme range of motion requirements","Gymnastics-level flexibility","Overhead shoulder mobility beyond basic","Deep backbending capabilities","Advanced yoga postures","Martial arts flexibility","Dance or performance flexibility","Contortion-level ranges","Complex movement patterns","Sport-specific flexibility beyond running"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"18 miles at conversational pace","whyThisTarget":"150% overshoot of race distance builds aerobic base for 31-mile effort."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2000 ft/hr for 6 hours (12,000 ft total)","whyThisTarget":"150% overshoot of 8,000 ft race gain ensures uphill power endurance."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 controlled reps per leg","whyThisTarget":"Essential eccentric quad control for thousands of downhill steps."},{"exerciseId":"b2000000-0000-0000-0000-000000000005","exerciseName":"Push-Up Max Set","graduationTarget":"35 unbroken reps","whyThisTarget":"Upper body endurance for trekking pole use over 6+ hours."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"Confidence level 3/5 on Class 2-3 terrain","whyThisTarget":"Basic scrambling comfort for technical trail sections and off-trail navigation."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds with heels flat","whyThisTarget":"Hip and ankle mobility for efficient uphill stride mechanics."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4 inches knee-to-wall distance","whyThisTarget":"Adequate dorsiflexion for steep uphill hiking without calf strain."}]}',
14, 'active');

-- 11. Colorado 14er Class 3-4
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Colorado 14er (Class 3-4)', 'Capitol Peak / Longs Peak',  '{"capitol peak", "longs peak", "14er class 3", "14er class 4", "capitol peak knife edge"}', 'scramble', 'advanced', 'Technical Colorado 14ers with exposed scrambling (Class 3-4).', 14265, 5000, 14, 1, 'Class 3-4', '["high-altitude", "exposure", "scrambling"]',
'{"cardio":72,"strength":68,"climbing_technical":78,"flexibility":55}',
'{"cardio":"All-day stamina at altitude","strength":"Leg endurance and grip security","climbing_technical":"Confident exposed scrambling movement","flexibility":"Hip and ankle range"}',
'{"cardio":{"summary":"Technical 14ers demand sustained aerobic capacity at altitude over 10+ hour days with significant elevation gain. The cardio system must handle long approaches, maintain performance above 12,000 feet, and sustain focus during technical sections when fatigued.","keyComponents":["sustained aerobic base","altitude tolerance","uphill hiking efficiency","energy management over 10+ hours","maintaining pace with elevation gain","recovery between technical sections","conversational breathing during approaches","leg endurance on steep terrain","pack-carrying stamina","consistent output over long distances"],"irrelevantComponents":["sprint speed","anaerobic power","VO2 max intervals","track running speed","flat terrain pace","short burst capacity","road racing tactics","speed endurance under 2 hours","explosive cardio movements","high-intensity interval training"]},"strength":{"summary":"Class 3-4 scrambling requires leg strength for steep terrain and upper body endurance for extended handholds. Core stability becomes critical on exposed sections where balance and control prevent falls.","keyComponents":["leg endurance on steep terrain","grip strength for sustained handholds","core stability on exposure","single-leg strength for high steps","upper body pulling endurance","calf strength for toe placements","hip stability on uneven terrain","shoulder endurance for mantling","pack-carrying strength","fatigue resistance in stabilizing muscles"],"irrelevantComponents":["maximum bench press","olympic lifting technique","powerlifting strength","explosive jumping power","heavy overhead pressing","bicep isolation strength","tricep isolation work","bodybuilding muscle mass","maximum deadlift capacity","competitive lifting metrics"]},"climbing_technical":{"summary":"Class 3-4 scrambling demands confident movement on exposed terrain where a fall could be fatal. Technical skills focus on route-finding, efficient movement patterns, and maintaining composure on airy sections.","keyComponents":["exposure tolerance","efficient scrambling movement","route-finding skills","balance on loose rock","confidence on airy terrain","downclimbing ability","rock quality assessment","body positioning on slabs","controlled breathing under stress","decision-making on difficult moves"],"irrelevantComponents":["sport climbing redpoint ability","bouldering power moves","crack climbing technique","aid climbing skills","big wall efficiency","multipitch rope management","traditional gear placement","advanced rescue techniques","ice climbing skills","alpine technical climbing grades"]},"flexibility":{"summary":"Scrambling requires basic hip and ankle mobility for high stepping and varied foot placements. Limited flexibility demands but sufficient range prevents injury and allows efficient movement patterns.","keyComponents":["hip flexor length for high steps","ankle dorsiflexion for steep terrain","calf flexibility for toe placements","hip external rotation","basic squat mobility","spinal extension for looking up routes","shoulder mobility for reaching holds","thoracic spine rotation"],"irrelevantComponents":["extreme hip flexibility","advanced yoga poses","splits capability","overhead shoulder mobility","spinal hyperextension","hamstring flexibility beyond 90 degrees","deep backbend capacity","gymnastic-level mobility","dance-specific ranges","martial arts flexibility demands"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"20+ miles","whyThisTarget":"Builds aerobic base for 14+ hour days with sustained energy output at altitude."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"7500 ft/hr","whyThisTarget":"Exceeds 5000ft objective gain rate to ensure comfortable pace on technical terrain."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 per leg","whyThisTarget":"Provides knee stability and eccentric control for steep descents and high steps."},{"exerciseId":"b2000000-0000-0000-0000-000000000003","exerciseName":"Weighted Pull-Ups","graduationTarget":"8 bodyweight","whyThisTarget":"Ensures grip endurance and upper body strength for sustained handholds on exposed sections."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4","whyThisTarget":"Confident movement on Class 3-4 terrain is essential for safety on exposed Colorado 14er routes."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"45s","whyThisTarget":"Sufficient hip and ankle mobility for high steps and varied foot placements on scrambling terrain."}]}',
12, 'active');

-- 12. Enchantments Traverse
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Enchantments Traverse', 'Snow Lakes to Stuart Lake',  '{"enchantments", "enchantments traverse", "enchantment lakes"}', 'hike', 'intermediate', 'Epic point-to-point traverse through the Enchantment Lakes basin. 18 miles with 4,500ft gain.', 7800, 4500, 18, 1, 'Class 1-2', '["endurance", "long-day", "alpine-lakes"]',
'{"cardio":75,"strength":65,"climbing_technical":30,"flexibility":50}',
'{"cardio":"All-day endurance for eighteen miles","strength":"Load-bearing stability over rocky terrain","climbing_technical":"Light scrambling confidence and balance","flexibility":"Hip and ankle mobility for terrain"}',
'{"cardio":{"summary":"The Enchantments Traverse demands exceptional aerobic endurance for 18 miles of sustained hiking across varied alpine terrain. The 4,500ft elevation gain spread over the full distance requires efficient energy systems and pacing discipline rather than explosive climbing power.","keyComponents":["Sustained aerobic base for 8-12 hour efforts","Efficient uphill hiking pace management","Energy system recovery between climbs","Consistent output over varied terrain","Mental endurance for long days","Heat dissipation and hydration management","Pace discipline to avoid early burnout","Leg turnover endurance on long descents","Breathing efficiency at moderate altitude"],"irrelevantComponents":["Sprint power or anaerobic capacity","High-intensity interval performance","Explosive climbing bursts","Short-duration maximum efforts","Competition pacing strategies","Track or road running speed","VO2 max ceiling performance","Race-specific power zones","Technical climbing endurance","Heavy pack hauling strength"]},"strength":{"summary":"Moderate strength demands focused on load-bearing stability and injury prevention over long distances on uneven terrain. The relatively light technical demands mean basic hiking strength trumps climbing-specific power.","keyComponents":["Single-leg stability on uneven surfaces","Eccentric quad control on long descents","Hip stability for lateral movements","Core endurance for pack stability","Basic upper body for light scrambling","Ankle stability on loose rock","Knee tracking strength","Glute activation for uphill power"],"irrelevantComponents":["Maximum pulling strength","Heavy weighted exercises","Explosive power movements","Advanced climbing strength","Heavy pack carrying capacity","Maximum squat or deadlift numbers","Competition-level strength ratios","Complex movement patterns","High-load carrying endurance","Dynamic climbing movements"]},"climbing_technical":{"summary":"Minimal technical demands with occasional Class 2 scrambling requiring basic balance and route-finding confidence. Movement skills focus on efficient hiking and simple rock navigation rather than climbing technique.","keyComponents":["Class 2 scrambling confidence","Basic balance on exposed terrain","Route-finding on marked trails","Efficient hiking rhythm","Rock-hopping technique","Stream crossing balance","Downhill control and foot placement","Basic exposure comfort"],"irrelevantComponents":["Advanced rock climbing technique","Rope handling skills","Multi-pitch systems","Technical anchor building","Complex movement sequences","Advanced route-finding","Rescue techniques","High-angle rock skills","Belaying or rappelling","Advanced scrambling grades"]},"flexibility":{"summary":"Standard hiking mobility needs with emphasis on hip and ankle range of motion for varied terrain navigation and injury prevention over long distances.","keyComponents":["Hip flexor length for long uphill strides","Ankle dorsiflexion for steep descents","Basic squat depth for rest positions","Calf flexibility for varied terrain","Hip external rotation for side-hilling","Thoracic spine mobility for pack comfort","Hamstring length for high steps"],"irrelevantComponents":["Advanced yoga poses","Extreme range of motion","Overhead shoulder mobility","Complex movement patterns","Competition-level flexibility","Advanced stretching techniques","Contortion-level abilities","Sport-specific flexibility beyond hiking","Advanced hip mobility","Gymnastic-level ranges"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"12-15 miles","whyThisTarget":"Builds aerobic base equivalent to 150% of the traverse distance for comfortable all-day endurance."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2000+ ft/hr","whyThisTarget":"Ensures efficient climbing pace at 150% of typical Enchantments elevation gain rate."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 per leg","whyThisTarget":"Provides eccentric quad control needed for long rocky descents without knee pain."},{"exerciseId":"b2000000-0000-0000-0000-000000000005","exerciseName":"Push-Up Max Set","graduationTarget":"20 reps","whyThisTarget":"Ensures basic upper body strength for occasional hand-assisted scrambling moves."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"3-4 on 1-5 scale","whyThisTarget":"Comfortable confidence on Class 2 terrain with occasional exposed sections."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Adequate hip and ankle mobility for comfortable rest positions and high rock steps."}]}',
8, 'active');

-- 13. John Muir Trail
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('John Muir Trail', 'Happy Isles to Whitney',  '{"john muir trail", "jmt", "john muir", "jmt thru-hike"}', 'backpacking', 'advanced', 'Iconic 211-mile thru-hike from Yosemite to Mt Whitney summit. 14-21 days.', 14505, 47000, 211, 18, 'Class 1', '["multi-day", "heavy-pack", "high-altitude", "endurance"]',
'{"cardio":80,"strength":70,"climbing_technical":35,"flexibility":60}',
'{"cardio":"Multi-week aerobic base for distance","strength":"Heavy pack endurance and stability","climbing_technical":"Basic navigation and off-trail confidence","flexibility":"Joint mobility for pack comfort"}',
'{"cardio":{"summary":"The JMT demands exceptional aerobic endurance for 18 days of 10-14 hour hiking with significant elevation gain daily. Sustained Zone 2 capacity and uphill hiking efficiency with a heavy pack are critical for completing long trail days while maintaining energy reserves.","keyComponents":["Multi-day aerobic endurance","Sustained uphill hiking pace","Heavy pack cardio efficiency","High altitude adaptation","Back-to-back long day recovery","Zone 2 fat burning capacity","Elevation gain stamina","Late-day energy maintenance","Cardiovascular durability","Oxygen debt management"],"irrelevantComponents":["Sprint power","Anaerobic threshold intervals","Short burst recovery","Explosive cardio movements","High-intensity interval training","Racing pace development","Power endurance","Lactate buffering","Neuromuscular power","Peak heart rate training"]},"strength":{"summary":"JMT requires sustained strength endurance for carrying 40-50lb packs over varied terrain for weeks. Focus on legs, core, and postural muscles that resist fatigue under load during long hiking days.","keyComponents":["Heavy pack carrying endurance","Uphill hiking leg strength","Single-leg stability on rocks","Core endurance under load","Postural strength for pack weight","Glute activation and power","Knee stability on descents","Grip strength for trekking poles","Foot and ankle strength","Multi-hour load tolerance"],"irrelevantComponents":["Maximum lift strength","Olympic lift power","Bench press capacity","Pull-up max strength","Short-duration strength","Explosive power movements","Heavy deadlift capacity","Upper body hypertrophy","Sprint strength","Plyometric power"]},"climbing_technical":{"summary":"The JMT is primarily Class 1 trail hiking with occasional Class 2 scrambling over passes. Technical demands are minimal but basic off-trail navigation and comfort on exposed terrain are helpful.","keyComponents":["Basic scrambling confidence","Off-trail route finding","Rock hopping balance","Exposure comfort on passes","Basic mountaineering awareness","Weather assessment skills","Stream crossing technique","Loose rock navigation","Basic first aid knowledge","Emergency shelter skills"],"irrelevantComponents":["Advanced rope work","Multi-pitch climbing","Technical rescue skills","Ice climbing technique","Advanced anchor building","Lead climbing skills","Big wall techniques","Crevasse rescue","Technical rappelling","Advanced route planning"]},"flexibility":{"summary":"Adequate mobility prevents injury and discomfort during weeks of repetitive hiking motion with a heavy pack. Hip flexors, ankles, and thoracic spine need maintenance flexibility for pack comfort and efficient stride.","keyComponents":["Hip flexor length for stride","Ankle dorsiflexion for uphills","Thoracic spine extension under pack","Calf flexibility for descents","IT band mobility","Shoulder mobility for pack straps","Basic movement quality","Morning stiffness management","Daily mobility maintenance","Pack-induced tension relief"],"irrelevantComponents":["Advanced yoga poses","Extreme range of motion","Gymnastic flexibility","Overhead mobility","Deep hip external rotation","Spinal hyperextension","Advanced stretching techniques","Contortion-level flexibility","Performance flexibility","Sport-specific mobility"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"15+ miles at conversational pace","whyThisTarget":"Demonstrates the aerobic base needed for 12+ hour hiking days over multiple weeks."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3500+ ft/hr @ 40lb pack","whyThisTarget":"Exceeds typical JMT daily elevation gain rates with realistic pack weight for comfort margin."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25+ controlled reps per leg","whyThisTarget":"Provides knee stability and eccentric strength needed for long descents with pack weight."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500+ meters in 10min @ 50lb","whyThisTarget":"Matches typical JMT pack weight and demonstrates sustained carrying capacity over time."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4/5 confidence on Class 3 terrain","whyThisTarget":"JMT passes occasionally require Class 2-3 scrambling and comfort with exposure."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"90+ second hold","whyThisTarget":"Demonstrates hip and ankle mobility needed for varied terrain and camp setup tasks."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"5+ inches knee-to-wall distance","whyThisTarget":"Adequate ankle mobility prevents strain during long uphill sections and rocky terrain."}]}',
14, 'active');

-- 14. Kilimanjaro
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Kilimanjaro', 'Machame Route',  '{"kilimanjaro", "kili", "kilimanjaro machame", "mount kilimanjaro"}', 'hike', 'intermediate', 'Highest peak in Africa via the popular Machame Route. 6-7 day trek to 19,341ft.', 19341, 13000, 37, 7, 'Class 1', '["high-altitude", "multi-day", "endurance"]',
'{"cardio":75,"strength":65,"climbing_technical":25,"flexibility":55}',
'{"cardio":"Seven days uphill endurance power","strength":"Heavy pack leg strength endurance","climbing_technical":"Basic trail navigation skills","flexibility":"Hip ankle mobility prevention"}',
'{"cardio":{"summary":"Kilimanjaro demands exceptional aerobic endurance for 6+ hour hiking days at extreme altitude where oxygen is 50% of sea level. The cardio system must efficiently deliver oxygen to working muscles while carrying a multi-day pack uphill for a week straight.","keyComponents":["sustained uphill hiking endurance","high-altitude oxygen efficiency","multi-day energy system recovery","heavy pack cardiovascular adaptation","Zone 2 aerobic base development","hiking-specific movement patterns","fatigue resistance over consecutive days","elevation gain capacity per hour","long-duration steady-state cardio","altitude acclimatization fitness"],"irrelevantComponents":["sprint speed","anaerobic power","interval training intensity","cycling-specific fitness","swimming endurance","court sport agility","explosive cardio bursts","high-intensity threshold work","short-duration efforts","sport-specific ball skills"]},"strength":{"summary":"Strength demands center on carrying a loaded pack uphill for hours while maintaining knee stability and preventing injury. Lower body strength endurance is critical, with core stability supporting heavy loads over uneven terrain.","keyComponents":["loaded pack carrying capacity","uphill hiking leg strength","knee joint stability under load","single-leg balance and control","hip stability for uneven terrain","core strength for pack support","grip endurance for trekking poles","calf strength for sustained uphill","glute activation under fatigue","postural strength for long days"],"irrelevantComponents":["maximum deadlift strength","explosive power movements","upper body pressing strength","Olympic lift technique","bench press capacity","sprint acceleration power","jumping ability","throwing strength","gymnastics strength skills","maximum squat 1RM"]},"climbing_technical":{"summary":"Kilimanjaro is a Class 1 hiking trail requiring only basic trail navigation and walking skills. No technical climbing ability is needed, just confidence moving on well-maintained paths.","keyComponents":["basic trail navigation","walking on loose rock","using trekking poles effectively","pacing and energy management","basic mountain safety awareness","weather recognition skills","altitude sickness recognition","gear management on trail"],"irrelevantComponents":["rock climbing technique","rope handling skills","belaying ability","anchor building","rappelling technique","lead climbing skills","multi-pitch systems","rescue techniques","ice climbing skills","scrambling on exposure"]},"flexibility":{"summary":"Flexibility needs are moderate, focused on preventing common hiking injuries through adequate hip and ankle mobility. Good flexibility supports efficient hiking mechanics and reduces strain from repetitive uphill motion.","keyComponents":["hip flexor mobility for uphill stride","ankle dorsiflexion for steep terrain","calf flexibility for descent","IT band mobility prevention","hip internal rotation for pack comfort","thoracic spine mobility for breathing","hamstring flexibility for long steps","glute activation mobility"],"irrelevantComponents":["extreme range of motion","gymnastic flexibility","overhead mobility","spinal hyperextension","advanced yoga poses","shoulder flexibility","wrist mobility","neck rotation range","deep backbend capacity","split flexibility"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3000 ft/hr with 25lb pack","whyThisTarget":"Exceeds Kilimanjaro''s ~1800 ft/hr pace requirement to build altitude buffer."},{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"12 miles continuous","whyThisTarget":"Builds aerobic base exceeding daily 6-8 mile hiking distances."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Ensures knee stability for thousands of downhill steps on descent days."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"400m in 10min with 25lb pack","whyThisTarget":"Matches typical Kilimanjaro pack weight for sustained carrying endurance."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"Confidence level 3","whyThisTarget":"Class 1 trail requires only basic comfort on maintained hiking paths."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Ensures hip and ankle mobility for efficient uphill hiking stride."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4 inches","whyThisTarget":"Provides adequate ankle mobility for steep uphill terrain navigation."}]}',
10, 'active');

-- 15. Tour du Mont Blanc
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Tour du Mont Blanc', 'Full Circuit (Counter-clockwise)',  '{"tour du mont blanc", "tmb", "tmb trek", "tour mont blanc"}', 'backpacking', 'intermediate', 'Classic 105-mile circuit around the Mont Blanc massif. 10-12 days with 32,000ft total gain.', 8900, 32000, 105, 11, 'Class 1', '["multi-day", "heavy-pack", "endurance", "european-alps"]',
'{"cardio":75,"strength":70,"climbing_technical":25,"flexibility":50}',
'{"cardio":"Multi-day endurance with heavy pack","strength":"Load-bearing stamina for long days","climbing_technical":"Trail navigation and basic exposure","flexibility":"Joint mobility for pack comfort"}',
'{"cardio":{"summary":"The TMB demands exceptional aerobic endurance to sustain 8-12 hour hiking days across varied terrain for 11 consecutive days. The high daily elevation gains (averaging 3,000ft/day) combined with pack weight creates a massive aerobic workload that must be maintained day after day.","keyComponents":["Multi-day endurance capacity","Sustained uphill hiking power","Heavy pack aerobic efficiency","Recovery between long days","Zone 2 aerobic base","Hiking-specific cardiovascular adaptation","High daily volume tolerance","Elevation gain endurance","Pack weight cardiovascular stress","Consistent daily output"],"irrelevantComponents":["Sprint power","Anaerobic threshold","VO2 max intervals","Short burst capacity","High-intensity intervals","Speed work","Track running","Cycling-specific fitness","Swimming endurance","Power lifting cardio"]},"strength":{"summary":"Strength demands center on load-bearing endurance and pack stability rather than maximal strength. The legs must handle repetitive step-ups and descents while the core and back stabilize a heavy pack through long days of uneven terrain.","keyComponents":["Pack-bearing core stability","Repetitive step-up endurance","Downhill braking strength","Hip stability under load","Postural endurance with pack","Grip strength for trekking poles","Ankle stability on varied terrain","Load-carrying capacity","Anti-fatigue leg strength","Multi-day strength maintenance"],"irrelevantComponents":["Maximum squat strength","Bench press power","Olympic lift technique","Sprint power","Jump height","Single-rep maximums","Powerlifting movements","Upper body pulling power","Explosive strength","Short-duration max efforts"]},"climbing_technical":{"summary":"Technical demands are minimal as the TMB follows well-marked trails with only basic scrambling sections. However, comfort with exposure, navigation skills, and confidence on varied terrain become important for safety and efficiency.","keyComponents":["Trail navigation confidence","Basic scrambling comfort","Exposure tolerance","Route-finding skills","Terrain reading ability","Weather assessment","Emergency decision-making","Basic first aid knowledge","Pack management skills","Multi-day planning"],"irrelevantComponents":["Rock climbing technique","Rope work skills","Advanced anchor systems","Crack climbing","Face climbing technique","Multi-pitch systems","Technical rescue","Ice climbing skills","High-angle rescue","Advanced climbing grades"]},"flexibility":{"summary":"Flexibility requirements focus on pack comfort and injury prevention during repetitive hiking motions. Good hip and ankle mobility prevents compensation patterns that lead to overuse injuries during the long daily distances.","keyComponents":["Hip flexor mobility for long strides","Ankle dorsiflexion for steep terrain","Thoracic spine extension under pack load","Hip rotation for varied terrain","Calf flexibility for descents","IT band mobility","Shoulder mobility for pack straps","Lower back flexibility","Hamstring length for step-ups","Overall movement quality"],"irrelevantComponents":["Extreme flexibility ranges","Advanced yoga positions","Gymnastic mobility","Overhead flexibility","Spinal hyperextension","Advanced stretching techniques","Contortion-level mobility","Dance flexibility","Martial arts flexibility","Performance flexibility"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2500 ft gain/hr @ 35lb pack","whyThisTarget":"Exceeds daily TMB elevation rate (1500 ft/hr average) to build comfortable buffer for sustained multi-day performance."},{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"12+ miles","whyThisTarget":"Develops aerobic base exceeding daily TMB distance (9.5 miles average) for strong endurance foundation."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000001","exerciseName":"Loaded Pack Squat","graduationTarget":"15 reps @ 35lb pack weight","whyThisTarget":"Matches typical TMB pack weight for repetitive hiking strength demands."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 per leg controlled","whyThisTarget":"Builds eccentric control for thousands of daily descent steps while preventing knee injuries."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500m @ 35lb in 10 min","whyThisTarget":"Develops pack-carrying endurance matching TMB load for extended periods."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4 on 1-5 scale","whyThisTarget":"TMB has minimal technical sections but confidence with basic exposure prevents anxiety on narrow ledges."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Ensures hip and ankle mobility for comfortable stride length and pack adjustments during long days."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4+ inches","whyThisTarget":"Adequate ankle mobility prevents compensation patterns during steep ascents and technical descents."}]}',
10, 'active');
